from sympy import *

def verify(answer) -> bool:
    a, b = symbols('a b', real=True)
    try:
        expr = sympify(str(answer).strip(), locals={'a': a, 'b': b})
    except Exception:
        return False
    for A in range(-3, 4):
        for B in range(-3, 4):
            if A < B:
                try:
                    if simplify(expr.subs({a: A, b: B}) - 2*B) != 0:
                        return False
                except Exception:
                    return False
    return True

from sympy import Interval, sympify

def verify(answer) -> bool:
    low, high = -13, 3

    # Direct Interval check
    try:
        if isinstance(answer, Interval):
            return (answer.start == low and answer.end == high and
                    not answer.left_open and not answer.right_open)
    except Exception:
        pass

    # Try to interpret via sympy sympify (allowing "Interval(-13, 3)")
    try:
        obj = sympify(str(answer), locals={'Interval': Interval})
        if isinstance(obj, Interval):
            return (obj.start == low and obj.end == high and
                    not obj.left_open and not obj.right_open)
    except Exception:
        pass

    # If it's an iterable like [-13, 3] or (-13, 3)
    try:
        if hasattr(answer, '__iter__'):
            vals = list(answer)
            if len(vals) == 2:
                a = float(vals[0])
                b = float(vals[1])
                return (a == low and b == high)
    except Exception:
        pass

    # Fallback: parse from string with common delimiters
    try:
        s = str(answer).strip()
        for ch in '[](){}':
            s = s.replace(ch, ' ')
        s = s.replace('to', ' ').replace(';', ' ').replace(':', ' ').replace(',', ' ')
        parts = [p for p in s.split() if p]
        nums = []
        for p in parts:
            try:
                nums.append(float(p))
            except Exception:
                pass
        if len(nums) >= 2:
            return (nums[0] == low and nums[1] == high)
    except Exception:
        pass

    return False

