import math

def verify(answer) -> bool:
    # Enumerate all seatings and count favorable ones
    people = ['A1','A2','B1','B2','C1','C2']
    partners = {'A1':'A2','A2':'A1','B1':'B2','B2':'B1','C1':'C2','C2':'C1'}
    total = 0
    favorable = 0
    for perm in permutations(people):
        total += 1
        pos = {perm[i]: i for i in range(6)}
        if abs(pos['A1'] - pos['A2']) == 1 and abs(pos['B1'] - pos['B2']) == 1 and abs(pos['C1'] - pos['C2']) == 1:
            favorable += 1
    prob = PyFraction(favorable, total)  # exact reduced fraction

    s = str(answer).strip()
    try:
        if '/' in s:
            return PyFraction(s) == prob
        if s.endswith('%'):
            val = float(s[:-1].strip()) / 100.0
            return abs(val - (prob.numerator / prob.denominator)) < 1e-12
        # try integer or float
        try:
            ival = int(s)
            return math.isclose(float(ival), prob.numerator / prob.denominator, rel_tol=0, abs_tol=1e-12)
        except:
            fval = float(s)
            return math.isclose(fval, prob.numerator / prob.denominator, rel_tol=0, abs_tol=1e-12)
    except:
        return False

