def verify(answer) -> bool:
    # Defensive integer parse attempt (per instructions)
    try:
        _ = int(str(answer).strip())
    except Exception:
        pass

    # Try to extract a 3D vector from various formats
    v = None
    try:
        # If it's already a sympy Matrix
        if isinstance(answer, Matrix):
            if answer.shape == (3, 1):
                v = [sympify(answer[i, 0]) for i in range(3)]
            elif answer.shape == (1, 3):
                v = [sympify(answer[0, i]) for i in range(3)]
        # If it's a list/tuple
        if v is None and hasattr(answer, "__iter__") and not isinstance(answer, (str, bytes)):
            arr = list(answer)
            if len(arr) == 3:
                v = [sympify(arr[0]), sympify(arr[1]), sympify(arr[2])]
        # If it's a string like "(x,y,z)" or "[x, y, z]"
        if v is None and isinstance(answer, str):
            s = answer.strip()
            for ch in "[](){}":
                s = s.replace(ch, " ")
            if "," in s:
                parts = [p.strip() for p in s.split(",") if p.strip() != ""]
            else:
                parts = [p for p in s.split() if p]
            if len(parts) == 3:
                v = [sympify(parts[0]), sympify(parts[1]), sympify(parts[2])]
    except Exception:
        return False

    if v is None or len(v) != 3:
        return False

    a = Matrix([1, 1, 1])
    vM = Matrix(v)

    try:
        dot_ok = (a.dot(vM) == 2)
        cross_ok = (a.cross(vM) == Matrix([1, -2, 1]))
        return bool(dot_ok and cross_ok)
    except Exception:
