    try:
        cand_int = int(s)
        c = Fraction(cand_int, 1)
    except Exception:
        try:
            c = Fraction(s)
        except Exception:
            return False

    def has_real_root(cval):
        # For 2x^2 + 5x + c = 0, discriminant D = 25 - 8c
        D = Fraction(25,1) - Fraction(8,1)*cval
        return D >= 0

    # Must have at least one real root at c
    if not has_real_root(c):
        return False

    # And for any positive increment (tested over a grid), there should be no real root
    for n in range(1, 101):
        if has_real_root(c + Fraction(1, n)):
            return False

    return True

