def verify(answer) -> bool:
    from fractions import Fraction as PyFraction

    target = PyFraction(19, 10)  # Half of 3 4/5

    s = str(answer).strip()

    # First try integer parsing as required
    try:
        if int(s) == target:
            return True
    except:
        pass

    def parse_fraction(text):
        text = text.strip()
        # Mixed number: "a b/c"
        if " " in text:
            parts = text.split()
            if len(parts) == 2 and "/" in parts[1]:
                try:
                    whole = int(parts[0])
                    num, den = parts[1].split("/")
                    num = int(num); den = int(den)
                    if den == 0:
                        return None
                    frac = PyFraction(num, den)
                    # Handle sign on whole number if any
                    if whole >= 0:
                        return PyFraction(whole, 1) + frac
                    else:
                        return PyFraction(whole, 1) - frac
                except:
                    return None
        # Simple fraction: "a/b"
        if "/" in text:
            try:
                num, den = text.split("/")
                num = int(num); den = int(den)
                if den == 0:
                    return None
                return PyFraction(num, den)
            except:
                return None
        # Decimal or other numeric string
        try:
            return PyFraction(text)
        except:
            return None

    val = parse_fraction(s)
    return val == target

