def verify(answer) -> bool:
    try:
        s = str(answer).strip().lower().replace(" ", "")
    except Exception:
        return False

    # Allow optional binary suffixes
    if s.endswith("_2"):
        s = s[:-2]
    if s.endswith("₂"):
        s = s[:-1]
    if s.startswith("0b"):
        s = s[2:]

    # Must contain a radix point
    if "." not in s:
        return False

    # Validate characters
    allowed = set("01.")
    if any(ch not in allowed for ch in s):
        return False

    # Split parts
    try:
        left, right = s.split(".")
    except ValueError:
        return False  # multiple dots

    # Allow empty left/right but ensure overall has at least one digit
    if (left == "" and right == ""):
        return False
    if any(ch not in "01" for ch in left if ch != ""):
        return False
    if any(ch not in "01" for ch in right if ch != ""):
        return False

    # Compute exact value as a rational
    val = PyFraction(0, 1)
    if left != "":
        val += PyFraction(int(left, 2), 1)
    if right != "":
        denom = 1 << len(right)
        numer = int(right, 2)
        val += PyFraction(numer, denom)

    return val == PyFraction(3, 16)

